object Solution {
  /**
    * Computes (base^exp) % mod
    */
  def power(base: Long, exp: Long, mod: Long): Long = {
    var res = 1L
    var b = base % mod
    var e = exp
    while (e > 0) {
      if (e % 2 == 1) {
        res = (res * b) % mod
      }
      b = (b * b) % mod
      e /= 2
    }
    res
  }

  /**
    * Computes the modular inverse of n modulo mod using Fermat's Little Theorem.
    * Requires mod to be prime.
    */
  def modInverse(n: Long, mod: Long): Long = {
    power(n, mod - 2, mod)
  }

  /**
    * Precomputes factorials and inverse factorials for combinations.
    */
  class Combinatorics(val maxN: Int, val mod: Long) {
    val fact = Array.ofDim[Long](maxN + 1)
    val invFact = Array.ofDim[Long](maxN + 1)

    val precompute() = {
      fact[0] = 1L
      for (i <- 1 to maxN) {
        fact(i) = (fact(i - 1) * i) % mod
      }
      invFact(maxN) = modInverse(fact(maxN), mod)
      for (i <- maxN - 1 down to 0) {
        invFact(i) = (invFact(i + 1) * (i + 1)) % mod
      }
    }

    /**
      * Computes nCk % mod
      */
    def combinations(n: Int, k: Int): Long = {
      if (k < 0 || k > n) 0L
      else {
        var res = fact(n)
        res = (res * invFact(k)) % mod
        res = (res * invFact(n - k)) % mod
        res
      }
    }
  }

  /**
    * Returns the number of possible direction assignments such that person at pos sees exactly k people.
    * @param n Total number of people (0 to n-1).
    * @param pos Index of the person in question.
    * @param k The exact number of people person at pos must see.
    * @return The number of valid assignments modulo 10^9 + 7.
    */
  def solve(n: Long, pos: Long, k: Long): Long = {
    val MOD: Long = 1000000007L
    val N_int = n.toInt
    val POS_int = pos.toInt
    val K_int = k.toInt

    // Number of people to the left of pos (indices 0 to pos-1)
    val leftCount = POS_int
    // Number of people to the right of pos (indices pos+1 to n-1)
    val rightCount = N_int - 1 - POS_int

    // --- Analysis for the left side (i < pos) ---
    // Person i < pos is visible if and only if they choose 'L'.
    // There are 'leftCount' people on the left.
    // We need 'l_visible' people among them to choose 'L' such that l_visible <= K_int.
    // The remaining (leftCount - l_visible) people must choose 'R'.

    // --- Analysis for the right side (i > pos) ---
    // Person i > pos is visible if and only if they choose 'R'.
    // There are 'rightCount' people on the right.
    // We need 'r_visible' people among them to choose 'R' such that r_visible <= K_int.
    // The remaining (rightCount - r_visible) people must choose 'L'.

    // Total visible count = l_visible + r_visible = K_int.
    // So, we need l_visible + r_visible = K_int, subject to:
    // 0 <= l_visible <= leftCount
    // 0 <= r_visible <= rightCount

    // The number of ways to achieve exactly l_visible on the left:
    // Choose l_visible people out of leftCount to choose 'L'. The rest choose 'R'.
    // Ways_L(l_visible) = C(leftCount, l_visible)

    // The number of ways to achieve exactly r_visible on the right:
    // Choose r_visible people out of rightCount to choose 'R'. The rest choose 'L'.
    // Ways_R(r_visible) = C(rightCount, r_visible)

    val comb = new Combinatorics(N_int, MOD)
    comb.precompute()

    var totalWays = 0L

    // Iterate over all possible numbers of visible people on the left (l_visible)
    for (l_visible <- 0 to Math.min(K_int, leftCount)) {
      // Required visible people on the right
      val r_visible = K_int - l_visible

      // Check if r_visible is possible
      if (r_visible >= 0 && r_visible <= rightCount) {
        // Number of ways to get l_visible on the left
        val waysLeft = comb.combinations(leftCount, l_visible)

        // Number of ways to get r_visible on the right
        val waysRight = comb.combinations(rightCount, r_visible)

        // Total ways for this split: waysLeft * waysRight
        val currentWays = (waysLeft * waysRight) % MOD
        totalWays = (totalWays + currentWays) % MOD
      }
    }

    // --- Contribution of person at pos ---
    // The choice of direction for the person at 'pos' does not affect the count 'k'.
    // Person at 'pos' can choose 'L' or 'R' (2 choices).
    val posChoiceMultiplier = 2L

    val finalAnswer = (totalWays * posChoiceMultiplier) % MOD

    finalAnswer
  }
}
